codeExamples.code:
int first(int[] a) { return a[0]; }          // O(1)

boolean contains(int[] a, int x) {             // O(n)
  for (int value : a) if (value == x) return true;
  return false;
}

void printPairs(int[] a) {                     // O(n^2)
  for (int left : a)
    for (int right : a)
      System.out.println(left + "," + right);
}
